ACircleAOETargetActor::ACircleAOETargetActor()
{
	PrimaryActorTick.bCanEverTick = true;

	// Set a default value for AOERadius
	AOERadius = 300.0f;

	// Set up the AOE Decal component
	AOEDecal = CreateDefaultSubobject<UDecalComponent>(TEXT("AOEDecal"));
	RootComponent = AOEDecal;

