3. In the `ACircleAOETargetActor` class, implement the Tick method to update the location based on the player confirmation or input, which might be from a trace or mouse/controller input:
```cpp
void ACircleAOETargetActor::Tick(float DeltaTime)
{
	Super::Tick(DeltaTime);

	// Get the player controller and ability system component
	APlayerController* PlayerController = Cast<APlayerController>(GetWorld()->GetFirstPlayerController());
	if (!PlayerController) { return; }

	// Perform a LineTrace from player's viewpoint to get a hit location on the ground
	FVector TraceStart, TraceEnd, TraceDirection;
	PlayerController->GetPlayerViewPoint(TraceStart, TraceDirection);
	TraceEnd = TraceStart + TraceDirection * 10000.0f;

	FHitResult HitResult;
	FCollisionQueryParams QueryParams;
	QueryParams.AddIgnoredActor(this);

	if (GetWorld()->LineTraceSingleByChannel(HitResult, TraceStart, TraceEnd, ECC_Visibility, QueryParams))
	{
		// Set the Decal's location to the hit location
		SetActorLocation(HitResult.Location);
	}
}
```

